  ('heelevel3-988e0de1-moex-00025', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '有關「薪工循環」之敘述，下列何者錯誤？', '["由薪資部門人員驗證工作計工單及員工計時卡是否一致，是有效的內部控制程序", "以現金支付所僱用臨時工之日薪時，領取日薪之工人需填簽收據是必要的管控程序", "為免發生員工由他人代為打卡之情況，打卡鐘應放置於明顯處由大眾監督，並由管理員隨 時注意，是必要的內部控制", "查核與小規模受查者攸關之控制作業，通常較著重收入、採購循環，而薪工循環因交易金 額較小，非屬主要與重要者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
